_____javascript
const data = await new Promise((resolve, reject) => {
  if (!document.body) return reject(new Error("No page body to capture"))
  const w = Math.max(document.documentElement.scrollWidth, document.body.scrollWidth, window.innerWidth)
  const h = Math.max(document.documentElement.scrollHeight, document.body.scrollHeight, window.innerHeight)
  const canvas = document.createElement("canvas")
  canvas.width = w
  canvas.height = h
  const ctx = canvas.getContext("2d")
  ctx.fillStyle = "#fff"
  ctx.fillRect(0, 0, w, h)
  ctx.fillStyle = "#000"
  ctx.font = "16px sans-serif"
  ctx.fillText("Screenshot capture placeholder; browser capture API not available in this runtime.", 20, 40)
  canvas.toBlob(blob => {
    if (!blob) return reject(new Error("Failed to create image blob"))
    const a = document.createElement("a")
    const url = URL.createObjectURL(blob)
    a.href = url
    a.download = "screenshot.png"
    a.click()
    setTimeout(() => URL.revokeObjectURL(url), 1000)
    resolve({ downloaded: true, bytes: blob.size })
  }, "image/png")
})
return data

