(async () => {
  const canvas = document.createElement("canvas")
  canvas.width = window.innerWidth * devicePixelRatio
  canvas.height = window.innerHeight * devicePixelRatio
  const ctx = canvas.getContext("2d")
  ctx.fillStyle = "#fff"
  ctx.fillRect(0, 0, canvas.width, canvas.height)
  ctx.fillStyle = "#000"
  ctx.font = `${16 * devicePixelRatio}px sans-serif`
  ctx.fillText(`Screenshot unavailable via direct DOM capture in this runtime`, 20 * devicePixelRatio, 40 * devicePixelRatio)

  const blob = await new Promise(resolve => canvas.toBlob(resolve, "image/png"))
  const url = URL.createObjectURL(blob)
  const a = document.createElement("a")
  a.href = url
  a.download = "screenshot.png"
  a.click()
  setTimeout(() => URL.revokeObjectURL(url), 1000)
  return "Downloaded a generated PNG placeholder"
})()

